sql.where:
e.status = 1

    AND (
        e.book_title LIKE CONCAT('%', #{param.keyword}, '%')
        OR e.author LIKE CONCAT('%', #{param.keyword}, '%')
        OR e.tags LIKE CONCAT('%', #{param.keyword}, '%')
        OR e.publisher LIKE CONCAT('%', #{param.keyword}, '%')
    )


    AND e.category_id = #{param.categoryId}


    AND e.language = #{param.language}


    AND e.price >= #{param.minPrice}


    AND e.price <= #{param.maxPrice}


    AND EXISTS (
        SELECT 1 FROM tb_ebook_file ef2
        WHERE ef2.book_id = e.book_id
        AND UPPER(ef2.file_format) = UPPER(#{param.fileFormat})
    )

mapper.select:
SELECT
FROM tb_ebook e LEFT JOIN tb_category c ON e.category_id = c.category_id LEFT JOIN tb_ebook_file ef ON e.book_id = ef.book_id
GROUP BY e.book_id ORDER BY ${param.sqlOrderBy} LIMIT #{param.offset}, #{param.limit}

SELECT
FROM tb_ebook e LEFT JOIN tb_category c ON e.category_id = c.category_id LEFT JOIN tb_ebook_file ef ON e.book_id = ef.book_id WHERE e.tags LIKE CONCAT('%', #{tag}, '%') AND e.status = 1
AND e.book_id != #{excludeBookId}
GROUP BY e.book_id ORDER BY e.rating DESC, e.create_time DESC LIMIT #{limit}
